clickScript:
const hit = roomSelections.find((selection) => {
  return x >= selection.x && x < selection.x + selection.width && y >= selection.y && y < selection.y + selection.height;
});

state.talkCount = typeof state.talkCount === 'number' ? state.talkCount : 0;
state.wineCount = typeof state.wineCount === 'number' ? state.wineCount : 0;
state.hasSmile = state.hasSmile === true;
state.eyesClosed = state.eyesClosed === true;

if (!hit) {
  return null;
}

if (hit.name === 'talk') {
  if (state.eyesClosed) {
    state.eyesClosed = false;
    return originalGraphics('closeeyes');
  }

  state.talkCount += 1;
  if (state.talkCount === 1) {
    return displayText('You say hello.');
  }
  if (state.talkCount === 2) {
    return displayText('She listens.');
  }
  if (state.wineCount === 0) {
    return displayText('She eyes wine.');
  }
  if (!state.hasSmile) {
    state.hasSmile = true;
    return replaceGraphics('smile');
  }
  return displayText('She seems warm.');
}

if (hit.name === 'wine') {
  if (state.talkCount === 0) {
    return displayText('Say hello first.');
  }

  state.wineCount += 1;
  if (state.wineCount === 1) {
    return displayText('She takes a sip.');
  }
  if (!state.hasSmile) {
    state.hasSmile = true;
    return replaceGraphics('smile');
  }
  return displayText('Wine helps.');
}

if (hit.name === 'smile') {
  if (!state.hasSmile) {
    if (state.talkCount === 0 && state.wineCount === 0) {
      return displayText('Not yet.');
    }
    state.hasSmile = true;
    return replaceGraphics('smile');
  }
  return displayText('Already smiling.');
}

if (hit.name === 'closeeyes') {
  if (!state.hasSmile) {
    return displayText('Make her smile.');
  }
  state.eyesClosed = !state.eyesClosed;
  if (state.eyesClosed) {
    return replaceGraphics('closeeyes');
  }
  return originalGraphics('closeeyes');
}

return displayText('Talk wine smile.');
